-- ============================================================
-- ALTER TABLE: widen thyrocare_id column & add new columns
-- ============================================================
ALTER TABLE `test-web`.`thyrocare_products`
  MODIFY COLUMN `thyrocare_id` VARCHAR(100) NOT NULL;

-- ============================================================
-- ALTER TABLE: add new columns if they don't exist
-- ============================================================
DROP PROCEDURE IF EXISTS `test-web`.`add_columns_if_missing`;
DELIMITER $$
CREATE PROCEDURE `test-web`.`add_columns_if_missing`()
BEGIN
  IF NOT EXISTS (SELECT 1 FROM information_schema.COLUMNS
    WHERE TABLE_SCHEMA='test-web' AND TABLE_NAME='thyrocare_products' AND COLUMN_NAME='thyrocare_price') THEN
    ALTER TABLE `test-web`.`thyrocare_products`
      ADD COLUMN `thyrocare_price` DECIMAL(10,2) NULL COMMENT '40% above selling price';
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.COLUMNS
    WHERE TABLE_SCHEMA='test-web' AND TABLE_NAME='thyrocare_products' AND COLUMN_NAME='what_this_test_checks') THEN
    ALTER TABLE `test-web`.`thyrocare_products`
      ADD COLUMN `what_this_test_checks` TEXT NULL;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.COLUMNS
    WHERE TABLE_SCHEMA='test-web' AND TABLE_NAME='thyrocare_products' AND COLUMN_NAME='who_should_take_this_test') THEN
    ALTER TABLE `test-web`.`thyrocare_products`
      ADD COLUMN `who_should_take_this_test` TEXT NULL;
  END IF;
  IF NOT EXISTS (SELECT 1 FROM information_schema.COLUMNS
    WHERE TABLE_SCHEMA='test-web' AND TABLE_NAME='thyrocare_products' AND COLUMN_NAME='why_doctors_recommend') THEN
    ALTER TABLE `test-web`.`thyrocare_products`
      ADD COLUMN `why_doctors_recommend` TEXT NULL;
  END IF;
END$$
DELIMITER ;
CALL `test-web`.`add_columns_if_missing`();
DROP PROCEDURE IF EXISTS `test-web`.`add_columns_if_missing`;

